import mysql.connector
from mysql.connector import Error
import os

def main():
    # Get file path from user input
    file_path = input("Enter file path: ")

    try:
        # Enable local_infile in MySQL config and Python connector
        cnx = mysql.connector.connect(
            user='username',
            password='password',
            host='localhost',
            database='database'
        )
        cursor = cnx.cursor()
        
        # Set local_infile to 1
        query = "SET GLOBAL local_infile = 1;"
        cursor.execute(query)
        
        # Get file path from user input and execute LOAD DATA INFILE statement
        query = "LOAD DATA INFILE '{}' INTO TABLE table_name FIELDS TERMINATED BY ',' ENCLOSED BY '\"' LINES TERMINATED BY '\\n';".format(file_path)
        cursor.execute(query)

        cnx.commit()
        
    except Error as e:
        print(f"Error: {e}")
    
    finally:
        if (cnx.is_connected()):
            cursor.close()
            cnx.close()

if __name__ == "__main__":
    main()